  {"id":"avf-metalwork-006","category":"metalwork","subject":"Iron Tsuba — Age Patina vs Artificial Aging","authentic_markers":[{"feature":"Natural iron oxide patina (deep brown to black)","detail":"Layered oxidation built up over centuries","detection_method":"Cross-section microscopy"},{"feature":"Pitting pattern consistent with age","detail":"Natural pitting from atmospheric corrosion","detection_method":"Surface examination"}],"fake_markers":[{"feature":"Acid-induced artificial patina","detail":"Too uniform, lacks layered depth","common_in":"Modern reproductions and tourist items"},{"feature":"Painted or lacquered surface","detail":"Coating applied to hide modern steel","common_in":"Chinese mass-produced tsuba"}],"confidence_notes":"Iron patina development takes centuries and is extremely difficult to simulate convincingly at the microscopic level","sources":["Sasano, Early Japanese Sword Guards","Robert Haynes tsuba authentication papers"],"verified_by":"source_verified"},
